8426	\begin{lemma}[Pullback along an open immersion is the restriction functor]
8427	  \label{lem:restrictFunctorIsoPullback_mathlib}
8428	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
8429	  \mathlibok
8430	  \textit{Provided by Mathlib.}
8431	  For an open immersion \(f : X \to Y\), the restriction functor
8432	  \(\operatorname{restrictFunctor} f : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) is
8433	  naturally isomorphic to the module pullback functor \(f^* = \operatorname{pullback} f\). In
8434	  particular \(f^*\mathcal{M} \cong \mathcal{M}.\operatorname{restrict} f\) for every
8435	  \(\mathcal{O}_Y\)-module \(\mathcal{M}\).
8436	\end{lemma}
