8438	\begin{lemma}[Evaluation of a sheaf of modules preserves products]
8439	  \label{lem:evaluation_preserves_products_mathlib}
8440	  \lean{SheafOfModules.evaluationPreservesLimitsOfShape}
8441	  \mathlibok
8442	  \textit{Provided by Mathlib.}
8443	  For a sheaf of rings on a site and any object \(U\), the evaluation (sections-at-\(U\))
8444	  functor \(\operatorname{evaluation}\,U : \operatorname{SheafOfModules} \to \mathrm{Ab}\)
8445	  preserves limits of every shape; in particular it preserves products, so \(\Gamma(U,
8446	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(U, N_\sigma)\).
8447	\end{lemma}
