8449	\begin{lemma}[Sections over a binary coproduct scheme are a product]
8450	  \label{lem:coprodPresheafObjIso_mathlib}
8451	  \lean{AlgebraicGeometry.Scheme.coprodPresheafObjIso}
8452	  \mathlibok
8453	  \textit{Provided by Mathlib.}
8454	  For schemes \(X, Y\) and an open \(U\) of the coproduct \(X \amalg Y\), the structure-sheaf
8455	  sections over \(U\) decompose as the product of the sections over the two preimages:
8456	  \((X \amalg Y).\mathcal{O}(U) \cong X.\mathcal{O}(\operatorname{inl}^{-1} U) \times
8457	  Y.\mathcal{O}(\operatorname{inr}^{-1} U)\). This is the binary disjoint-union sheaf
8458	  decomposition that Lemma~\ref{lem:pushPull_sigma_iso} ports to the indexed,
8459	  \(\operatorname{SheafOfModules}\) setting.
8460	\end{lemma}
