8462	\begin{lemma}[Sections of a sheaf over a disjoint union are a product]
8463	  \label{lem:isProductOfDisjoint_mathlib}
8464	  \lean{TopCat.Sheaf.isProductOfDisjoint}
8465	  \mathlibok
8466	  \textit{Provided by Mathlib.}
8467	  For a sheaf \(F\) (valued in a category with products) on a topological space and two opens
8468	  \(U, V\) with \(U \sqcap V = \bot\) (disjoint), the sections over the union are the product
8469	  of the sections: \(F(U \sqcup V) \cong F(U) \times F(V)\). Iterated over a finite family,
8470	  this is the disjoint-union decomposition underlying Lemma~\ref{lem:pushPull_sigma_iso}.
8471	\end{lemma}
