8475	\begin{lemma}[The category of schemes is finitary extensive]
8476	  \label{lem:finitaryExtensive_scheme_mathlib}
8477	  \lean{AlgebraicGeometry.instFinitaryExtensiveScheme}
8478	  \mathlibok
8479	  \textit{Provided by Mathlib.}
8480	  The category \(\operatorname{Scheme}\) is finitary extensive: finite coproducts are disjoint
8481	  and universal (stable under pullback). In particular it is finitary pre-extensive and has
8482	  finite coproducts and pullbacks, so the abstract distributivity of
8483	  Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib} applies at \(\mathcal{C} = \operatorname{Scheme}\).
8484	\end{lemma}
