8486	\begin{lemma}[Coproducts distribute over the binary fibre product]
8487	  \label{lem:isIso_sigmaDesc_map_mathlib}
8488	  \lean{CategoryTheory.FinitaryPreExtensive.isIso_sigmaDesc_map}
8489	  \mathlibok
8490	  \textit{Provided by Mathlib.}
8491	  In a finitary pre-extensive category with pullbacks, for finite index types \(\iota, \iota'\),
8492	  a base \(S\), and families \((X_i \to S)_i\), \((Y_j \to S)_j\), the canonical map
8493	  \(\coprod_{(i,j)} (X_i \times_S Y_j) \to (\coprod_i X_i) \times_S (\coprod_j Y_j)\),
8494	  \(\operatorname{Sigma.desc}\) of the pullback maps, is an isomorphism. Taking one family to be a
8495	  singleton gives the one-sided distributivity
8496	  \((\coprod_i X_i) \times_S Y \cong \coprod_i (X_i \times_S Y)\) used in the induction of
8497	  Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8498	\end{lemma}
